#!/usr/bin/env python
# encoding: utf-8

'''
Класс для инициализации параметров об обсерватории
на текущий момент только 5 вариантов: САО, КрАО, boao, sanpedromartir,
'''

import numpy as np
from astropy import units as u
from astropy.coordinates import EarthLocation, Angle

class Observatory( dict ):
 def __init__(self, shortname):
  dict.__init__(self)
  self["shortname"] = shortname
  if self["shortname"] == "saoras":
   self.saoras()
  elif self["shortname"] == "boao":
   self.boao()
  elif self["shortname"] == "moletai":
   self.moletai()
  elif self["shortname"] == "SanPedroMartir":
   self.SanPedroMartir()
  elif self["shortname"] == "india_1.3m":
   self.india_1_3m()
  else:
   self.crimea()
  self.getCoord()
  self.getTimezone()
  self.getTitle()

 def saoras(self):
  self["Latitude"] = Angle('41:26:29.175', unit=u.deg)
  self["Longitude"] =  Angle('43:39:12.7', unit=u.deg)
  self["Altitude"] = 2070.0*u.m
  self["UtcOffset"] = 3*u.hour  # UTC+03
  self["longname"] = "Special Astrophysical Observatory"

 def moletai(self):
  '''
  55°18′57″ с. ш. 25°33′48″ в. д. 
  '''
  #http://mao.tfai.vu.lt/mao/en
  self["Latitude"] = Angle('55:18:57', unit=u.deg) 
  self["Longitude"] =  Angle('25:33:48', unit=u.deg)
  self["Altitude"] = 200.0*u.m
  self["UtcOffset"] = 2*u.hour  # UTC+02
  self["longname"] = "Moletai"

 def boao(self):
  self["Latitude"] = Angle('9.2', unit=u.deg)
  self["Longitude"] =  Angle('128.9', unit=u.deg)
  self["Altitude"] = 1100*u.m
  self["UtcOffset"] = 9*u.hour  # UTC+09
  self["longname"] = "Bohyunsan Optical Astronomy Observatory"

 def SanPedroMartir(self):
  '''
    Coordinates 	31.0439°N 115.4637°W
    Coordinates: 31.0439°N 115.4637°W
    Altitude 	2,800 meters (9,200 ft)
  '''
  self["Latitude"] = Angle('31.0439', unit=u.deg)
  self["Longitude"] =  Angle('-115.4637', unit=u.deg)
  self["Altitude"] = 2800*u.m
  self["UtcOffset"] = -7*u.hour  # UTC-07  UTC Offset Standard Time
  self["longname"] = "National Astronomical Observatory (Mexico)"


 def india_1_3m (self):
  '''
   29.361603,79.684967,700m
   1.3m Telescope, ARIES, Devasthal Campus, Nainital
    Coordinates 	31.0439°N 115.4637°W
    Coordinates: 31.0439°N 115.4637°W
    Altitude 	2,800 meters (9,200 ft)
  '''
  self["Latitude"] = Angle('29.361603', unit=u.deg)
  self["Longitude"] =  Angle('79.684967', unit=u.deg)
  self["Altitude"] = 2450*u.m
  self["UtcOffset"] = 5.5*u.hour  # UTC+05:30  UTC Offset Standard Time
  self["longname"] = "1.3m Telescope, ARIES, Devasthal Campus, Nainital"


 def crimea(self):
  #http://www.crao.crimea.ua/ru/instrumenty/43-zerkalnyj-teleskop-im-akad-g-a-shajna-260-sm-ztsh
  self["Latitude"] = Angle('44:43:41', unit=u.deg)
  self["Longitude"] =  Angle('34:00:57', unit=u.deg)
  self["Altitude"] = 600.0*u.m
  self["UtcOffset"] = 3*u.hour  # UTC+03
  self["longname"] = "Crimean Astrophysical Observatory"

 def getTitle(self):
  self["Title"] = "{} {} {} {}".format( 
    self["longname"],
    self["Latitude"].to_string(unit=u.degree, sep=('deg', 'm', 's')),
    self["Longitude"].to_string(unit=u.degree, sep=('deg', 'm', 's')),
    self["Altitude"]
    )
 def getCoord(self):
  self["Coord"] = EarthLocation( lat=self["Latitude"], lon=self["Longitude"], height= self["Altitude"])
  self["EarthLocation"] = self["Coord"]

 def getTimezone(self):
  self["Timezone"] = "UTC+{:02d}".format( int(self["UtcOffset"].value) )

 def __str__(self):
  _ret = ""
  _ret += "shortname {shortname}\n".format( ** self )
  _ret += "longname {longname}\n".format( ** self )
  _ret += "title {Title}\n".format( ** self )
  _ret += "timezone {Timezone}\n".format( ** self )
#  for keyword in self.keys():
#  _ret += "{keyword}: {value}\n".format( keyword=keyword, value=self[keyword] )
  return _ret


if __name__ == "__main__":
 observatory = Observatory("saoras")
 print( observatory.values() )
 observatory = Observatory("crimea")
 print( observatory )
